mapper.select:
select id, submission_id, testcase_id, case_index, judge_status, run_time_ms, memory_kb, expected_output, actual_output, error_message, created_at from submission_case_results where submission_id = #{submissionId}
and judge_status <> 'ACCEPTED'
order by case_index asc, id asc limit #{size} offset #{offset}
